Fix the bug in the ConsistentHashRing class so that remove_node correctly removes all virtual node replicas that were added by add_node.

```python
import hashlib
import bisect

class ConsistentHashRing:
    def __init__(self, replicas=3):
        self.replicas = replicas
        self.ring = []  # sorted list of virtual node hashes
        self.vnode_map = {}  # hash -> physical node

    def _hash(self, key):
        return int(hashlib.md5(key.encode('utf-8')).hexdigest(), 16)

    def add_node(self, node):
        for i in range(self.replicas):
            vnode_key = f"{node}-replica-{i}"
            vnode_hash = self._hash(vnode_key)
            bisect.insort(self.ring, vnode_hash)
            self.vnode_map[vnode_hash] = node

    def remove_node(self, node):
        for i in range(1, self.replicas + 1):
            vnode_key = f"{node}-replica-{i}"
            vnode_hash = self._hash(vnode_key)
            try:
                self.ring.remove(vnode_hash)
            except ValueError:
                pass
            if vnode_hash in self.vnode_map:
                del self.vnode_map[vnode_hash]

    def get_node(self, key):
        if not self.ring:
            return None
        key_hash = self._hash(key)
        idx = bisect.bisect_right(self.ring, key_hash)
        idx = idx % len(self.ring)
        return self.vnode_map[self.ring[idx]]
```

